patch:
@@ -1073,6 +1073,12 @@ body.layoutDesktop .nodesktop {
   display: none;
 }

+body.deviceMobile .noDeviceMobile,
+body.deviceTablet .noDeviceTablet,
+body.deviceDesktop .noDeviceDesktop {
+  display: none;
+}
+
 body {
   &.layoutTablet, &.layoutDesktop {
 	.mobileonly { display: none}
@@ -1083,4 +1089,13 @@ body {
   &.layoutDesktop, &.layoutMobile {
 	.tabletonly { display: none}
   }
+  &.deviceTablet, &.deviceDesktop {
+	.mobileDeviceOnly { display: none}
+  }
+  &.deviceTablet, &.deviceMobile {
+	.desktopDeviceOnly {display: none}
+  }
+  &.deviceDesktop, &.deviceMobile {
+	.tabletDeviceOnly { display: none}
+  }
 }

@@ -1073,6 +1073,12 @@ body.layoutDesktop .nodesktop {
   display: none;
 }

+body.deviceMobile .noDeviceMobile,
+body.deviceTablet .noDeviceTablet,
+body.deviceDesktop .noDeviceDesktop {
+  display: none;
+}
+
 body {
   &.layoutTablet, &.layoutDesktop {
 	.mobileonly { display: none}
@@ -1083,4 +1089,13 @@ body {
   &.layoutDesktop, &.layoutMobile {
 	.tabletonly { display: none}
   }
+  &.deviceTablet, &.deviceDesktop {
+	.mobileDeviceOnly { display: none}
+  }
+  &.deviceTablet, &.deviceMobile {
+	.desktopDeviceOnly {display: none}
+  }
+  &.deviceDesktop, &.deviceMobile {
+	.tabletDeviceOnly { display: none}
+  }
 }
